for i in {0..20} ; do echo 1 1 | gmx_mpi trjconv -s ../window${i}/window${i}.tpr -f ../window${i}/window${i}.xtc -pbc mol -center -o pbcmol.xtc ; echo 1 1 | gmx_mpi trjconv -s ../window${i}/window${i}.tpr -f pbcmol.xtc -pbc cluster -o pbcclust.xtc ; echo 1 1 | gmx_mpi trjconv -s ../window${i}/window${i}.tpr -f pbcclust.xtc -fit progressive -o tmp${i}.xtc ; rm pbcmol.xtc pbcclust.xtc ; done ; gmx_mpi trjcat -cat -f tmp?.xtc tmp??.xtc -o lig2-solv-us_merged.xtc ; gmx_mpi trjconv -s ../window0/window0.tpr -f lig2-solv-us_merged.xtc -dump 0 -o v1.pdb
